	@Test
	void pureJoinIsCommutativeUnderBagSemantics() {
		StatementPattern a = pattern("s", P1, "x");
		StatementPattern b = pattern("s", P2, "y");

		TupleExpr original = new Join(a.clone(), b.clone());
		TupleExpr reordered = new Join(b.clone(), a.clone());

		EquivalenceResult result = new AlgebraEquivalenceChecker().check(original, reordered);

		assertEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(), result::getReason);
		assertTrue(result.getEvidence().orElseThrow() instanceof NormalizationProof);
	}

	@Test
	void duplicateUnionIsNotBagEquivalent() {
		StatementPattern a = pattern("s", P1, "o");
		TupleExpr duplicated = new Union(a.clone(), a.clone());

		EquivalenceResult result = counterexampleChecker().check(duplicated, a.clone());

		assertEquals(EquivalenceStatus.NOT_EQUIVALENT, result.getStatus(), result::getReason);
		Counterexample counterexample = (Counterexample) result.getEvidence().orElseThrow();
		assertFalse(counterexample.getEvaluationCase().getStatements().isEmpty());
		assertNotNull(counterexample.getOriginalOutcome());
	}

